-- Create "user_redeem_code_redemptions" table
CREATE TABLE "user_redeem_code_redemptions" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "user_id" bigint NOT NULL,
  "redeem_code_id" bigint NOT NULL,
  "code_digest" character varying NOT NULL,
  "type" character varying NOT NULL,
  "amount" character varying NOT NULL DEFAULT '0.00000000',
  "currency" character varying NOT NULL DEFAULT 'USD',
  "balance_before" character varying NOT NULL DEFAULT '0.00000000',
  "balance_after" character varying NOT NULL DEFAULT '0.00000000',
  "billing_ledger_id" bigint NULL,
  "user_subscription_id" bigint NULL,
  "redeemed_at" timestamptz NOT NULL,
  "metadata_json" jsonb NULL,
  PRIMARY KEY ("id")
);
-- Create index "userredeemcoderedemption_code_digest" to table: "user_redeem_code_redemptions"
CREATE INDEX "userredeemcoderedemption_code_digest" ON "user_redeem_code_redemptions" ("code_digest");
-- Create index "userredeemcoderedemption_redeem_code_id" to table: "user_redeem_code_redemptions"
CREATE INDEX "userredeemcoderedemption_redeem_code_id" ON "user_redeem_code_redemptions" ("redeem_code_id");
-- Create index "userredeemcoderedemption_user_id_redeem_code_id" to table: "user_redeem_code_redemptions"
CREATE UNIQUE INDEX "userredeemcoderedemption_user_id_redeem_code_id" ON "user_redeem_code_redemptions" ("user_id", "redeem_code_id");
-- Create index "userredeemcoderedemption_user_id_redeemed_at" to table: "user_redeem_code_redemptions"
CREATE INDEX "userredeemcoderedemption_user_id_redeemed_at" ON "user_redeem_code_redemptions" ("user_id", "redeemed_at");
